using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Tianyou.Domain.Entities;
using Tianyou.Infrastructure.Data;
using Tianyou.Application.Security;

namespace Tianyou.Application.Services;

/// <summary>
/// 代码生成服务
/// </summary>
public class CodeGeneratorService
{
    private readonly TianyouDbContext _context;
    private readonly ILogger<CodeGeneratorService> _logger;

    public CodeGeneratorService(TianyouDbContext context, ILogger<CodeGeneratorService> logger)
    {
        _context = context;
        _logger = logger;
    }

    public async Task<string> GenerateEntityCodeAsync(Guid entityId)
    {
        var entity = await _context.EntityDefinitions
            .Include(e => e.Fields)
            .FirstOrDefaultAsync(e => e.Id == entityId);

        if (entity == null)
        {
            _logger.LogWarning("生成代码失败：实体不存在 - EntityId: {EntityId}", entityId);
            throw new Exception("实体不存在");
        }

        // XSS防护：清理实体名称和描述
        var safeEntityName = XssProtector.SanitizeIdentifier(entity.EntityName, "实体名称");
        var safeDescription = XssProtector.SanitizeHtml(entity.Description);

        var code = $@"using System.ComponentModel.DataAnnotations;

namespace Tianyou.Domain.Entities;

/// <summary>
/// {safeEntityName}
/// </summary>
public class {safeEntityName}
{{
";
        foreach (var field in entity.Fields)
        {
            // XSS防护：清理字段名称
            var safeFieldName = XssProtector.SanitizeIdentifier(field.FieldName, "字段名称");
            var safeMaxLength = field.MaxLength.HasValue ? $"(MaxLength = {field.MaxLength})" : "";

            code += $@"    [Required{safeMaxLength}]
    public {GetCSharpType(field.FieldType)} {safeFieldName} {{ get; set; }}
";
        }

        code += @"}
";

        _logger.LogInformation("代码生成成功 - EntityId: {EntityId}, EntityName: {EntityName}", entityId, safeEntityName);

        return code;
    }

    public async Task<CodeTemplate> CreateTemplateAsync(string templateName, string templateType, 
        string templateContent, string? description = null, string? language = "csharp")
    {
        // XSS防护：清理所有输入
        var safeTemplateName = XssProtector.SanitizeHtml(templateName);
        var safeTemplateType = XssProtector.SanitizeHtml(templateType);
        var safeTemplateContent = XssProtector.ValidateAndSanitize(templateContent, "模板内容");
        var safeDescription = XssProtector.SanitizeHtml(description);
        var safeLanguage = XssProtector.SanitizeHtml(language);

        var template = new CodeTemplate
        {
            Id = Guid.NewGuid(),
            TemplateName = safeTemplateName,
            TemplateType = safeTemplateType,
            TemplateContent = safeTemplateContent,
            Description = safeDescription,
            Language = safeLanguage,
            IsSystem = false,
            CreatedAt = DateTime.UtcNow,
            UpdatedAt = DateTime.UtcNow
        };

        _context.CodeTemplates.Add(template);
        await _context.SaveChangesAsync();

        _logger.LogInformation("模板创建成功 - TemplateId: {TemplateId}, TemplateName: {TemplateName}", 
            template.Id, template.TemplateName);

        return template;
    }

    public async Task<List<CodeTemplate>> GetTemplatesAsync(string? templateType = null)
    {
        var query = _context.CodeTemplates.AsQueryable();

        if (!string.IsNullOrEmpty(templateType))
        {
            // XSS防护：清理模板类型
            var safeTemplateType = XssProtector.SanitizeHtml(templateType);
            query = query.Where(t => t.TemplateType == safeTemplateType);
        }

        var templates = await query.OrderBy(t => t.TemplateName).ToListAsync();

        _logger.LogInformation("查询模板列表 - TemplateType: {TemplateType}, Count: {Count}", 
            templateType ?? "all", templates.Count);

        return templates;
    }

    private string GetCSharpType(string fieldType)
    {
        return fieldType.ToLower() switch
        {
            "text" or "string" => "string",
            "number" or "int" => "int",
            "decimal" or "money" => "decimal",
            "bool" or "boolean" => "bool",
            "date" or "datetime" => "DateTime",
            "guid" => "Guid",
            _ => "string"
        };
    }
}

using Microsoft.AspNetCore.Authentication.JwtBearer;
using Microsoft.EntityFrameworkCore;
using Microsoft.IdentityModel.Tokens;
using Microsoft.OpenApi.Models;
using System.Text;
using Tianyou.Application.Services;
using Tianyou.Infrastructure.Data;
using AspNetCoreRateLimit;

var builder = WebApplication.CreateBuilder(args);

// 添加数据库上下文（SQLite）
builder.Services.AddDbContext<TianyouDbContext>(options =>
    options.UseSqlite(builder.Configuration.GetConnectionString("DefaultConnection")));

// 配置速率限制
builder.Services.AddMemoryCache();
builder.Services.Configure<IpRateLimitOptions>(builder.Configuration.GetSection("IpRateLimiting"));
builder.Services.Configure<IpRateLimitPolicies>(builder.Configuration.GetSection("IpRateLimitPolicies"));
builder.Services.Configure<ClientRateLimitOptions>(builder.Configuration.GetSection("ClientRateLimiting"));
builder.Services.Configure<ClientRateLimitPolicies>(builder.Configuration.GetSection("ClientRateLimitPolicies"));
builder.Services.AddInMemoryRateLimiting();
builder.Services.AddSingleton<IRateLimitConfiguration, RateLimitConfiguration>();

// 添加服务
builder.Services.AddScoped<AuthService>();
builder.Services.AddScoped<EntityService>();
builder.Services.AddScoped<FormService>();
builder.Services.AddScoped<WorkflowService>();
builder.Services.AddScoped<PluginService>();
builder.Services.AddScoped<CodeGeneratorService>();
builder.Services.AddScoped<ReportService>();
builder.Services.AddScoped<NotificationService>();
builder.Services.AddScoped<TenantService>();

// 配置JWT认证
var jwtSettings = builder.Configuration.GetSection("Jwt");
// 从环境变量读取JWT密钥，如果不存在则使用配置文件中的值
var jwtKey = Environment.GetEnvironmentVariable("JWT_SECRET_KEY")
    ?? jwtSettings["Key"]
    ?? throw new InvalidOperationException("JWT密钥未配置！请设置环境变量JWT_SECRET_KEY或在appsettings.json中配置");
var key = Encoding.UTF8.GetBytes(jwtKey);

builder.Services.AddAuthentication(options =>
{
    options.DefaultAuthenticateScheme = JwtBearerDefaults.AuthenticationScheme;
    options.DefaultChallengeScheme = JwtBearerDefaults.AuthenticationScheme;
})
.AddJwtBearer(options =>
{
    options.TokenValidationParameters = new TokenValidationParameters
    {
        ValidateIssuer = true,
        ValidateAudience = true,
        ValidateLifetime = true,
        ValidateIssuerSigningKey = true,
        ValidIssuer = jwtSettings["Issuer"],
        ValidAudience = jwtSettings["Audience"],
        IssuerSigningKey = new SymmetricSecurityKey(key),
        ClockSkew = TimeSpan.Zero
    };
});

builder.Services.AddAuthorization();
builder.Services.AddControllers();
builder.Services.AddEndpointsApiExplorer();

// 配置Swagger
builder.Services.AddSwaggerGen(c =>
{
    c.SwaggerDoc("v1", new OpenApiInfo
    {
        Title = "Tianyou API",
        Version = "v1",
        Description = "Tianyou低代码平台API",
        Contact = new OpenApiContact
        {
            Name = "Tianyou Team",
            Email = "support@tianyou.com"
        }
    });

    // 添加JWT认证
    c.AddSecurityDefinition("Bearer", new OpenApiSecurityScheme
    {
        Description = "JWT Authorization header using the Bearer scheme.",
        Name = "Authorization",
        In = ParameterLocation.Header,
        Type = SecuritySchemeType.ApiKey,
        Scheme = "Bearer"
    });

    c.AddSecurityRequirement(new OpenApiSecurityRequirement
    {
        {
            new OpenApiSecurityScheme
            {
                Reference = new OpenApiReference
                {
                    Type = ReferenceType.SecurityScheme,
                    Id = "Bearer"
                }
            },
            Array.Empty<string>()
        }
    });
});

// 配置CORS - 限制为特定域名
builder.Services.AddCors(options =>
{
    options.AddPolicy("AllowSpecificOrigins", policy =>
    {
        policy.WithOrigins(
                "http://192.168.50.251:8091",
                "http://localhost:8091",
                "http://localhost:5000",
                "http://127.0.0.1:8091",
                "http://127.0.0.1:5000"
              )
              .AllowAnyMethod()
              .AllowAnyHeader()
              .AllowCredentials();
    });
});

var app = builder.Build();

// 自动运行数据库迁移和种子数据
using (var scope = app.Services.CreateScope())
{
    var context = scope.ServiceProvider.GetRequiredService<TianyouDbContext>();
    context.Database.EnsureCreated();
    Console.WriteLine("✅ SQLite数据库已创建");
}

// 应用速率限制（在所有中间件之前）
app.UseIpRateLimiting();
app.UseClientRateLimiting();
Console.WriteLine("✅ 速率限制已启用");

// 开发环境启用Swagger（可通过环境变量覆盖）
var enableSwagger = app.Environment.IsDevelopment() || 
    builder.Configuration.GetValue<bool>("Swagger:Enabled", false);

if (enableSwagger)
{
    app.UseSwagger();
    app.UseSwaggerUI(c =>
    {
        c.SwaggerEndpoint("/swagger/v1/swagger.json", "Tianyou API v1");
        c.RoutePrefix = "swagger";
    });

    Console.WriteLine("⚠️  Swagger已启用 - 仅建议在开发环境使用");
}
else
{
    // 生产环境强制HTTPS重定向
    app.UseHttpsRedirection();
    Console.WriteLine("✅ Swagger已禁用（生产环境）");
}
app.UseCors("AllowSpecificOrigins");
app.UseAuthentication();
app.UseAuthorization();
app.MapControllers();

// 健康检查
app.MapGet("/health", () => Results.Ok("Healthy"));
app.MapGet("/", () => Results.Ok("Tianyou API is running!"));

app.Run();

using Microsoft.EntityFrameworkCore;
using Tianyou.Domain.Entities;

namespace Tianyou.Infrastructure.Data;

/// <summary>
/// Tianyou数据库上下文（SQLite）
/// </summary>
public class TianyouDbContext : DbContext
{
    public TianyouDbContext(DbContextOptions<TianyouDbContext> options) : base(options)
    {
    }

    // DbSet
    public DbSet<User> Users => Set<User>();
    public DbSet<Role> Roles => Set<Role>();
    public DbSet<Permission> Permissions => Set<Permission>();
    public DbSet<EntityDefinition> EntityDefinitions => Set<EntityDefinition>();
    public DbSet<FieldDefinition> FieldDefinitions => Set<FieldDefinition>();
    public DbSet<DynamicData> DynamicData => Set<DynamicData>();
    public DbSet<FormDefinition> FormDefinitions => Set<FormDefinition>();
    public DbSet<FormField> FormFields => Set<FormField>();
    public DbSet<WorkflowDefinition> WorkflowDefinitions => Set<WorkflowDefinition>();
    public DbSet<WorkflowInstance> WorkflowInstances => Set<WorkflowInstance>();
    public DbSet<WorkflowTask> WorkflowTasks => Set<WorkflowTask>();
    public DbSet<PluginDefinition> PluginDefinitions => Set<PluginDefinition>();
    public DbSet<CodeTemplate> CodeTemplates => Set<CodeTemplate>();
    public DbSet<ReportDefinition> ReportDefinitions => Set<ReportDefinition>();
    public DbSet<Notification> Notifications => Set<Notification>();
    public DbSet<Tenant> Tenants => Set<Tenant>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        base.OnModelCreating(modelBuilder);

        // 配置User实体
        modelBuilder.Entity<User>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.Username).IsUnique();
            entity.HasIndex(e => e.Email).IsUnique();
            entity.Property(e => e.Username).IsRequired().HasMaxLength(50);
            entity.Property(e => e.Email).IsRequired().HasMaxLength(100);
            entity.Property(e => e.PasswordHash).IsRequired();
            entity.Property(e => e.Status).HasDefaultValue("active");
        });

        // 配置Role实体
        modelBuilder.Entity<Role>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.RoleName).IsUnique();
            entity.HasIndex(e => e.RoleCode).IsUnique();
            entity.Property(e => e.RoleName).IsRequired().HasMaxLength(50);
            entity.Property(e => e.RoleCode).IsRequired().HasMaxLength(50);
        });

        // 配置Permission实体
        modelBuilder.Entity<Permission>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.PermissionName).IsUnique();
            entity.HasIndex(e => e.PermissionCode).IsUnique();
            entity.Property(e => e.PermissionName).IsRequired().HasMaxLength(100);
            entity.Property(e => e.PermissionCode).IsRequired().HasMaxLength(100);
        });

        // 配置多对多关系：User-Role
        modelBuilder.Entity<User>()
            .HasMany(u => u.Roles)
            .WithMany(r => r.Users);

        // 配置多对多关系：Role-Permission
        modelBuilder.Entity<Role>()
            .HasMany(r => r.Permissions)
            .WithMany(p => p.Roles);

        // 配置EntityDefinition实体
        modelBuilder.Entity<EntityDefinition>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.EntityName).IsUnique();
            entity.HasIndex(e => e.TableName).IsUnique();
            entity.Property(e => e.EntityName).IsRequired().HasMaxLength(100);
            entity.Property(e => e.TableName).IsRequired().HasMaxLength(100);
        });

        // 配置FieldDefinition实体
        modelBuilder.Entity<FieldDefinition>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => new { e.EntityDefinitionId, e.FieldName }).IsUnique();
            entity.Property(e => e.FieldName).IsRequired().HasMaxLength(100);
            entity.Property(e => e.FieldType).IsRequired().HasMaxLength(50);
            entity.HasOne(e => e.Entity)
                  .WithMany(e => e.Fields)
                  .HasForeignKey(e => e.EntityDefinitionId);
        });

        // 配置DynamicData实体
        modelBuilder.Entity<DynamicData>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasOne(e => e.Entity)
                  .WithMany()
                  .HasForeignKey(e => e.EntityDefinitionId);
        });

        // 配置FormDefinition实体
        modelBuilder.Entity<FormDefinition>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.FormName).IsUnique();
            entity.Property(e => e.FormName).IsRequired().HasMaxLength(100);
        });

        // 配置FormField实体
        modelBuilder.Entity<FormField>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasOne(e => e.Form)
                  .WithMany(f => f.Fields)
                  .HasForeignKey(e => e.FormDefinitionId);
        });

        // 配置WorkflowDefinition实体
        modelBuilder.Entity<WorkflowDefinition>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.WorkflowName).IsUnique();
            entity.Property(e => e.WorkflowName).IsRequired().HasMaxLength(100);
        });

        // 配置WorkflowInstance实体
        modelBuilder.Entity<WorkflowInstance>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Status).IsRequired().HasMaxLength(50);
            entity.HasOne(e => e.Workflow)
                  .WithMany(w => w.Instances)
                  .HasForeignKey(e => e.WorkflowDefinitionId);
        });

        // 配置WorkflowTask实体
        modelBuilder.Entity<WorkflowTask>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Status).IsRequired().HasMaxLength(50);
            entity.HasOne(e => e.Instance)
                  .WithMany(i => i.Tasks)
                  .HasForeignKey(e => e.WorkflowInstanceId);
        });

        // 配置PluginDefinition实体
        modelBuilder.Entity<PluginDefinition>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.PluginCode).IsUnique();
            entity.Property(e => e.PluginName).IsRequired().HasMaxLength(100);
            entity.Property(e => e.PluginCode).IsRequired().HasMaxLength(100);
        });

        // 配置CodeTemplate实体
        modelBuilder.Entity<CodeTemplate>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.TemplateName).IsUnique();
            entity.Property(e => e.TemplateName).IsRequired().HasMaxLength(100);
            entity.Property(e => e.TemplateType).IsRequired().HasMaxLength(50);
        });

        // 配置ReportDefinition实体
        modelBuilder.Entity<ReportDefinition>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.ReportName).IsUnique();
            entity.Property(e => e.ReportName).IsRequired().HasMaxLength(100);
            entity.Property(e => e.ReportType).IsRequired().HasMaxLength(50);
        });

        // 配置Notification实体
        modelBuilder.Entity<Notification>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Title).IsRequired().HasMaxLength(200);
            entity.Property(e => e.NotificationType).IsRequired().HasMaxLength(50);
            entity.Property(e => e.Channel).IsRequired().HasMaxLength(50);
        });

        // 配置Tenant实体
        modelBuilder.Entity<Tenant>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.TenantCode).IsUnique();
            entity.Property(e => e.TenantName).IsRequired().HasMaxLength(100);
            entity.Property(e => e.TenantCode).IsRequired().HasMaxLength(50);
            entity.Property(e => e.Status).IsRequired().HasMaxLength(20);
        });

        // 种子数据
        SeedData(modelBuilder);
    }

    private void SeedData(ModelBuilder modelBuilder)
    {
        // 默认角色
        modelBuilder.Entity<Role>().HasData(
            new Role
            {
                Id = Guid.Parse("11111111-1111-1111-1111-111111111111"),
                RoleName = "超级管理员",
                RoleCode = "super_admin",
                Description = "系统超级管理员",
                CreatedAt = DateTime.UtcNow
            },
            new Role
            {
                Id = Guid.Parse("22222222-2222-2222-2222-222222222222"),
                RoleName = "管理员",
                RoleCode = "admin",
                Description = "系统管理员",
                CreatedAt = DateTime.UtcNow
            },
            new Role
            {
                Id = Guid.Parse("33333333-3333-3333-3333-333333333333"),
                RoleName = "开发者",
